diagnostic_sql:
-- PGA usage and hit ratio
SELECT name, value FROM v$pgastat
WHERE name IN ('aggregate PGA target parameter','total PGA inuse','cache hit percentage','over allocation count');

-- Buffer cache size and hit rate
SELECT name, value FROM v$sysstat
WHERE name IN ('physical reads','physical reads cache','physical reads direct','session logical reads');

-- Reason cursors are not shared
SELECT sql_id, reason FROM v$sql_shared_cursor
WHERE sql_id = :sql_id FETCH FIRST 10 ROWS ONLY;

-- Hard parse rate
SELECT name, value FROM v$sysstat
WHERE name IN ('parse count (hard)','parse count (total)','parse count (failures)');

-- ORA-01555 frequency from alert log (manual review required)
-- Check DBA_SCHEDULER_JOB_RUN_DETAILS for long-running jobs overlapping with UNDO_RETENTION
SELECT value FROM v$parameter WHERE name = 'undo_retention';

-- Undo generation from AWR
SELECT name, value FROM v$sysstat
WHERE name IN ('undo change vector size','transaction rollbacks','user rollbacks');

-- Redo generation stats
SELECT name, value FROM v$sysstat
WHERE name IN ('redo size','redo writes','redo blocks written','redo log space requests','redo log space wait time');

-- Current parallel sessions
SELECT qcsid, count(*) AS slave_count, sql_id
FROM v$px_session GROUP BY qcsid, sql_id ORDER BY slave_count DESC;
